INSERT INTO `employees` VALUES ('asset_investment','资产设备专家','专注于资产分布分析、投资项目进度跟踪、资产价值评估和生产设备运营分析','1.1','资产','active','[\"D5\", \"D6\", \"D7\"]','[\"getTotalssets\", \"getAssetValue\", \"getPhysicalAssets\", \"getRegionalAnalysis\", \"getCategoryAnalysis\", \"getCategoryAnalysisTransparentTransmission\", \"getEquipmentFacilityAnalysisYoy\", \"getEquipmentFacilityAnalysis\", \"getEquipmentFacilityStatusAnalysis\", \"getEquipmentFacilityRegionalAnalysis\", \"getEquipmentFacilityWorthAnalysis\", \"getLandMaritimeAnalysisTransparentTransmission\", \"getHousingAnalysisYoy\", \"getLandMaritimeAnalysisYoy\", \"getLandMaritimeRegionalAnalysis\", \"getLandMaritimeWorthAnalysis\", \"getImportAssertAnalysisList\", \"planInvestAndPayYoy\", \"getFinishProgressAndDeliveryRate\", \"getInvestPlanByYear\", \"getCostProjectFinishByYear\", \"getCostProjectAmtByOwnerLgZoneName\", \"getCostProjectCurrentStageQtyList\", \"getOutOfPlanFinishProgressList\", \"getOutOfPlanProjectQtyYoy\", \"getPlanFinishByZone\", \"getPlanFinishByProjectType\", \"getDeliveryRate\", \"getEquipmentIndicatorOperationQty\", \"getEquipmentIndicatorUseCost\", \"getProductionEquipmentFaultNum\", \"getProductionEquipmentStatistic\", \"getOverviewQuery\", \"getEquipmentUsageRate\", \"getEquipmentServiceableRate\", \"getEquipmentFirstLevelClassNameList\", \"getContainerMachineHourRate\", \"getEquipmentEnergyConsumptionPerUnit\", \"getEquipmentFuelOilTonCost\", \"getEquipmentElectricityTonCost\", \"getProductEquipmentUsageRateByYear\", \"getProductEquipmentUsageRateByMonth\", \"getProductEquipmentRateByYear\", \"getProductEquipmentIntegrityRateByYear\", \"getProductEquipmentIntegrityRateByMonth\", \"getQuayEquipmentWorkingAmount\", \"getProductEquipmentDataAnalysisList\", \"getProductEquipmentWorkingAmountByYear\", \"getProductEquipmentWorkingAmountByMonth\", \"getProductEquipmentReliabilityByYear\", \"getProductEquipmentReliabilityByMonth\", \"getProductEquipmentUnitConsumptionByYear\", \"getProductEquipmentUnitConsumptionByMonth\"]','[\"skill_api_fetch\", \"skill_file_parse\", \"skill_web_search\", \"skill_desc_analysis\", \"skill_anomaly\", \"skill_attribution\", \"skill_prediction\", \"skill_chart_line\", \"skill_chart_bar\", \"skill_chart_waterfall\", \"skill_dashboard\", \"skill_summary_gen\", \"skill_report_html\", \"skill_report_docx\", \"skill_report_pptx\"]','[{\"id\": \"ai-simple-1\", \"tag\": \"数据查询\", \"type\": \"数据\", \"question\": \"当前资产净值及资产类型分布，以表格列出各类资产金额\"}, {\"id\": \"ai-simple-2\", \"tag\": \"数据查询\", \"type\": \"数据\", \"question\": \"当前设备运行状态统计（正常、维修、停用数量），以表格列出各类数量\"}, {\"id\": \"ai-chart-1\", \"tag\": \"图文分析\", \"type\": \"图表\", \"question\": \"2026年投资项目进度，以柱状图展示各项目完成率\"}, {\"id\": \"ai-chart-2\", \"tag\": \"图文分析\", \"type\": \"图表\", \"question\": \"2026年1-4月设备故障次数月度趋势，以折线图展示各月变化\"}, {\"id\": \"ai-report-q1\", \"tag\": \"深度报告\", \"type\": \"报告\", \"question\": \"生成2026年Q1资产投资运营综合报告（资产价值、投资进度、设备健康度），以 HTML 格式交付\"}]','{\"extra_slots\": [{\"name\": \"asset_category\", \"meaning\": \"资产类别（房屋/土地/海域/设备设施/金融资产）\", \"priority\": 8, \"required\": false, \"inferable\": true, \"allowed_values\": [\"房屋\", \"土地\", \"海域\", \"设备设施\", \"金融资产\"]}, {\"name\": \"project_type\", \"meaning\": \"项目类型（资本项目/成本项目/计划外项目）\", \"priority\": 9, \"required\": false, \"inferable\": true, \"allowed_values\": [\"资本项目\", \"成本项目\", \"计划外项目\"]}, {\"name\": \"project_status\", \"meaning\": \"项目状态筛选（在建/完工/未开工）\", \"priority\": 10, \"required\": false, \"inferable\": true, \"allowed_values\": [\"在建\", \"完工\", \"未开工\"]}, {\"name\": \"equipment_type\", \"meaning\": \"设备分类（一级：装卸/运输/起重/输送/特种；二级：岸桥/门机/RTG等）\", \"priority\": 11, \"required\": false, \"inferable\": true}], \"domain_keywords\": {\"D5\": [\"资产\", \"房屋\", \"土地\", \"海域\", \"设备设施\", \"实物资产\", \"金融资产\", \"原值\", \"净值\"], \"D6\": [\"投资\", \"资本项目\", \"成本项目\", \"计划进度\", \"交付率\", \"完成率\", \"计划外\"], \"D7\": [\"设备利用率\", \"完好率\", \"台时效率\", \"能耗\", \"单耗\", \"燃油\", \"电量\", \"设备故障\", \"MTBF\", \"可靠性\", \"机种\", \"岸桥\", \"RTG\", \"门机\"]}, \"slot_constraints\": {\"domain\": {\"default_value\": \"D5\", \"allowed_values\": [\"D5\", \"D6\", \"D7\"]}, \"data_granularity\": {\"allowed_values\": [\"port\", \"zone\", \"asset\", \"project\", \"company\", \"equipment\"]}}, \"system_prompt_suffix\": \"你是资产价值与投资项目分析师，专注于资产分布统计、资产价值评估、\\n投资项目进度跟踪、成本计划完成率分析，以及生产设备运营效能分析。\\n\"}','{\"prompt_suffix\": \"## 分析策略 Cookbook\\n\\n### 核心原则\\n- 有 startDate/endDate 参数的 API 能返回时间区间数据，适合趋势分析\\n- 只传单个 dateYear/dateMonth 的 API 通常只返回该时点快照，不可直接用于趋势\\n- 返回 num/typeName 透视格式的 API，需按 typeName 分组后提取各指标数值\\n\\n### D5 资产分析策略\\n- 资产按港区对比 → getRegionalAnalysis（num/typeName/ownerZone 透视格式）\\n- 资产按类别对比 → getCategoryAnalysis（num/typeName/assetTypeName 透视格式）\\n- 设备设施同比 → getEquipmentFacilityAnalysisYoy（num/typeName/dateYear 透视格式）\\n- 土地海域分析 → getLandMaritimeRegionalAnalysis（按港区面积/净值）\\n- 房屋同比 → getHousingAnalysisYoy\\n- 注意：D5 的 getRegionalAnalysis/getCategoryAnalysis 等返回透视格式，需用 typeName 分组解读\\n\\n### D6 投资分析策略\\n- 历年投资趋势 → getInvestPlanByYear（dateYear/finishInvestAmt/planInvestAmt/...，7行2019-2025，可做趋势）\\n- 成本项目历年 → getCostProjectFinishByYear（dateYear/projectQty/realFinishPayAmt/...）\\n- 各港区投资对比 → getPlanFinishByZone（ownerLgZoneName/planInvestAmt/finishInvestAmt/planPayAmt/finishPayAmt）\\n- 各港区成本项目 → getCostProjectAmtByOwnerLgZoneName（ownerLgZoneName/investAmt/finishPayAmt）\\n- 项目阶段分布 → getCostProjectCurrentStageQtyList（projectQty/projectCurrentStage/ownerLgZoneName）\\n- 投资完成进度归因 → 用 skill_chart_waterfall 对各港区完成/未完成做归因分析\\n- 注意：planInvestAndPayYoy 返回 dateYear/planInvestAmt/planPayAmt，是同比快照\\n\\n### D7 设备分析策略\\n- 设备概览 → getProductionEquipmentStatistic（num/secondLevelName 透视格式，39行按机种汇总）\\n- 设备利用率月度曲线 → getEquipmentUsageRate（usageRate/dateMonth）\\n- 设备完好率月度曲线 → getEquipmentServiceableRate（serviceableRate/dateMonth）\\n- 集装箱台时效率 → getContainerMachineHourRate（machineHourRate/dateMonth）\\n- 历年利用率趋势 → getProductEquipmentUsageRateByYear（usageRate/dateYear，4行2023-2026）\\n- 设备能耗曲线 → getEquipmentEnergyConsumptionPerUnit（workingAmount/dateMonth）\\n- 设备作业量指标 → getEquipmentIndicatorOperationQty（num/firstLevelName 透视格式）\\n- 设备成本指标 → getEquipmentIndicatorUseCost（num/firstLevelName 透视格式）\\n- 设备故障分析 → getProductionEquipmentFaultNum（num/dateMonth 透视格式）\\n- 注意：D7 很多 API 返回透视格式（num/typeName），需先按分组字段解析再分析\\n\\n### 图表选择\\n- 资产/设备按港区或类型对比 → skill_chart_bar\\n- 投资完成进度归因 → skill_chart_waterfall\\n- 月度趋势曲线（利用率/完好率/台时/能耗） → skill_chart_line\\n- 历年趋势对比 → skill_chart_line\\n\"}','2026-04-21 16:42:56','2026-04-23 18:25:01'),('customer_insight','市场客户专家','专注于战略客户贡献分析、客户结构洞察和市场商务数据','1.1','客户','active','[\"D3\"]','[\"getCustomerQty\", \"getCustomerTypeAnalysis\", \"getCustomerFieldAnalysis\", \"getCustomerCredit\", \"getStrategicCustomerThroughput\", \"getStrategicCustomers\", \"getCurStrategicCustomerContributionByCargoTypeThroughput\", \"getCurContributionRankOfStrategicCustomer\", \"getSumStrategyCustomerTrendAnalysis\", \"getCurStrategyCustomerTrendAnalysis\", \"getSumStrategicCustomerContributionByCargoTypeThroughput\", \"getSumContributionRankOfStrategicCustomer\", \"getTrendChart\", \"getKeyEnterprise\", \"getCumulativeKeyEnterprise\", \"getMonthlyRegionalThroughputAreaBusinessDashboard\", \"getCumulativeTrendChart\", \"investCorpShareholdingProp\"]','[\"skill_api_fetch\", \"skill_file_parse\", \"skill_web_search\", \"skill_desc_analysis\", \"skill_anomaly\", \"skill_attribution\", \"skill_prediction\", \"skill_chart_line\", \"skill_chart_bar\", \"skill_chart_waterfall\", \"skill_dashboard\", \"skill_summary_gen\", \"skill_report_html\", \"skill_report_docx\", \"skill_report_pptx\"]','[{\"id\": \"ci-simple-1\", \"tag\": \"数据查询\", \"type\": \"数据\", \"question\": \"当前战略客户总数及客户等级分布，以表格列出各等级客户数量\"}, {\"id\": \"ci-simple-2\", \"tag\": \"数据查询\", \"type\": \"数据\", \"question\": \"2026年4月 TOP10 战略客户吞吐量，以表格列出客户名称与数值\"}, {\"id\": \"ci-chart-1\", \"tag\": \"图文分析\", \"type\": \"图表\", \"question\": \"2026年1-4月战略客户贡献度月度趋势，以折线图展示稳定性\"}, {\"id\": \"ci-chart-2\", \"tag\": \"图文分析\", \"type\": \"图表\", \"question\": \"2026年4月各业务板块吞吐量占比，以饼图展示结构分布\"}, {\"id\": \"ci-report-q1\", \"tag\": \"深度报告\", \"type\": \"报告\", \"question\": \"生成2026年Q1战略客户洞察综合报告（客户画像、贡献度、流失风险、结构变化），以 HTML 格式交付\"}]','{\"extra_slots\": [{\"name\": \"client_name\", \"meaning\": \"指定客户名称（如某战略客户）\", \"priority\": 8, \"required\": false, \"inferable\": false}, {\"name\": \"ranking_metric\", \"meaning\": \"排名维度（吞吐量/收入/利润/货量）\", \"priority\": 9, \"required\": false, \"inferable\": true, \"allowed_values\": [\"吞吐量\", \"收入\", \"利润\", \"货量\"]}, {\"name\": \"ranking_top_n\", \"meaning\": \"排名取前 N 位（默认 10）\", \"priority\": 10, \"required\": false, \"inferable\": true}], \"domain_keywords\": {\"D2\": [\"商务驾驶舱\", \"市场\", \"重点企业\", \"业务板块\", \"吞吐量分析\"], \"D3\": [\"客户\", \"战略客户\", \"客户贡献\", \"客户信用\", \"客户结构\", \"排名\"]}, \"slot_constraints\": {\"domain\": {\"default_value\": \"D3\", \"allowed_values\": [\"D2\", \"D3\", \"D4\"]}, \"data_granularity\": {\"allowed_values\": [\"port\", \"zone\", \"company\", \"customer\", \"cargo\", \"business\"]}}, \"system_prompt_suffix\": \"你是市场商务与战略客户洞察专家，专注于客户贡献排名、客户趋势分析、\\n客户结构变化洞察、市场商务数据分析。\\n\"}','{\"prompt_suffix\": \"## 分析策略 Cookbook\\n\\n### 核心原则\\n- 有 startDate/endDate 或 date(yyyy-MM) 参数的 API 能做时间维度分析\\n- 无时间参数的 API（getCustomerQty/getCustomerTypeAnalysis/getStrategicCustomers）返回当前快照\\n- 返回 num/typeName 透视格式的 API，需按 typeName 分组后提取各指标数值\\n- getSumContributionRankOfStrategicCustomer 返回 clientName/num，注意目前数据可能全为零\\n\\n### D3 客户分析策略\\n**客户概览（静态快照）：**\\n- 客户总量 → getCustomerQty（totalQty/outPortQty/strategyClientQty/customerFilesNumber）\\n- 客户类型结构 → getCustomerTypeAnalysis（clientType/qty）\\n- 客户行业分析 → getCustomerFieldAnalysis（field/count/ratio）\\n- 战略客户名单 → getStrategicCustomers（displayCode/displayName，仅名单无业绩数据）\\n\\n**战略客户趋势分析（可做趋势）：**\\n- 当期月度趋势 → getCurStrategyCustomerTrendAnalysis（dateMonth/num/typeName 透视格式，多月×多指标）\\n- 历年累计趋势 → getSumStrategyCustomerTrendAnalysis（月份序列，长期趋势）\\n\\n**战略客户排名与贡献：**\\n- 当月按货类贡献 → getCurStrategicCustomerContributionByCargoTypeThroughput（cargoType/strategicThroughput/contributionRate）\\n- 累计按货类贡献 → getSumStrategicCustomerContributionByCargoTypeThroughput（categoryName/num）\\n- 当月排名 → getCurContributionRankOfStrategicCustomer（rank/clientName/throughput/contributionRate）\\n- 累计排名 → getSumContributionRankOfStrategicCustomer（clientName/num，注意数据可能为零）\\n\\n### D2 市场商务分析策略（与客户分析结合）\\n- 重点企业排名 → getKeyEnterprise（throughput/companyName/dateMonth，需传 businessSegment）\\n- 累计重点企业 → getCumulativeKeyEnterprise（rank/enterpriseName/cumulativeThroughput）\\n- 月度趋势（按板块）→ getTrendChart（throughput/businessSegment/dateMonth，需 businessSegment+startDate+endDate）\\n- 累计趋势（按板块）→ getCumulativeTrendChart（throughput/businessSegment/dateYear）\\n- 各港区当月 → getMonthlyRegionalThroughputAreaBusinessDashboard（num/typeName/zoneName 透视格式）\\n- 注意：D2 的透视格式 API 需按 typeName/zoneName 分组\\n\\n### 图表选择\\n- 客户排名/贡献 → skill_chart_bar（横向排名柱状图）\\n- 客户类型/行业占比 → skill_chart_bar（堆叠或分组柱状图）\\n- 月度趋势分析 → skill_chart_line\\n- 客户洞察报告 → 优先使用 PPT 格式（skill_report_pptx）\\n\"}','2026-04-21 16:42:56','2026-04-23 18:25:01'),('throughput_analyst','生产运营专家','专注于港口生产运营指标和市场商务吞吐量的数据分析','1.1','吞吐','active','[\"D1\", \"D2\"]','[]','[\"skill_api_fetch\", \"skill_file_parse\", \"skill_web_search\", \"skill_desc_analysis\", \"skill_anomaly\", \"skill_attribution\", \"skill_prediction\", \"skill_chart_line\", \"skill_chart_bar\", \"skill_chart_waterfall\", \"skill_dashboard\", \"skill_summary_gen\", \"skill_report_html\", \"skill_report_docx\", \"skill_report_pptx\"]','[{\"id\": \"tp-simple-1\", \"tag\": \"数据查询\", \"type\": \"数据\", \"question\": \"2026年4月全港吞吐量总量及各港区数量，以表格列出\"}, {\"id\": \"tp-simple-2\", \"tag\": \"数据查询\", \"type\": \"数据\", \"question\": \"2026年4月各业务板块（集装箱、散杂货、油化品、商品车）吞吐量，以表格列出\"}, {\"id\": \"tp-chart-1\", \"tag\": \"图文分析\", \"type\": \"图表\", \"question\": \"2026年1-4月全港吞吐量月度趋势，以折线图展示各月变化\"}, {\"id\": \"tp-chart-2\", \"tag\": \"图文分析\", \"type\": \"图表\", \"question\": \"2026年4月各港区吞吐量对比，以柱状图展示各港区差异\"}, {\"id\": \"tp-report-q1\", \"tag\": \"深度报告\", \"type\": \"报告\", \"question\": \"生成2026年Q1港口经营综合分析报告（吞吐量、结构占比、同比环比），以 HTML 格式交付\"}]','{\"extra_slots\": [{\"name\": \"business_type\", \"meaning\": \"业务类型（集装箱/散杂货/油化品/商品车/滚装）\", \"priority\": 8, \"required\": false, \"inferable\": true, \"allowed_values\": [\"集装箱\", \"散杂货\", \"油化品\", \"商品车\", \"滚装\"]}, {\"name\": \"cargo_type\", \"meaning\": \"货类细分（如铁矿石、煤炭、粮食等）\", \"priority\": 9, \"required\": false, \"inferable\": true}], \"domain_keywords\": {\"D1\": [\"吞吐量\", \"TEU\", \"集装箱\", \"散货\", \"泊位\", \"船舶\", \"商品车\", \"港存\", \"装卸效率\", \"交通管制\"], \"D2\": [\"商务驾驶舱\", \"市场\", \"重点企业\", \"业务板块\", \"当月吞吐\", \"累计吞吐\"]}, \"slot_constraints\": {\"domain\": {\"default_value\": \"D1\", \"allowed_values\": [\"D1\", \"D2\"]}, \"data_granularity\": {\"allowed_values\": [\"port\", \"zone\", \"company\", \"cargo\", \"business\"]}}, \"system_prompt_suffix\": \"你是吞吐量绩效分析师，专注于港口生产运营和市场商务领域。\\n擅长吞吐量目标完成分析、泊位效率对比、船舶动态监控、业务板块结构分析。\\n\"}','{\"prompt_suffix\": \"## 分析策略 Cookbook\\n\\n### 核心原则\\n- 有 startDate/endDate 参数的 API 能返回时间区间数据，适合趋势分析\\n- 只传单个 dateYear/dateMonth 的 API 通常只返回该时点快照，不可直接用于趋势\\n- getThroughputAndTargetThroughputTon/Teu 仅返回1行KPI汇总（targetQty/finishQty），不可用于趋势\\n\\n### D1 生产运营分析策略\\n**月度趋势分析（首选）：**\\n- 吞吐量月度趋势 → getThroughputAnalysisByYear（dateMonth/qty，16行当年+上年对比）\\n- 集装箱月度趋势 → getContainerThroughputAnalysisByYear（dateMonth/qty，TEU版）\\n- 年度各月吞吐含累计 → getPersonalCenterYearCargoThroughputTrend（regionName/yearId/monthId/tonQ/teuQ，月度×港区）\\n- 泊位占用率趋势 → getBerthOccupancyRateByRegion（regionName/dateMonth/rate，有startDate/endDate）\\n- 作业效率趋势 → getProductViewShipOperationRateTrend（monthId/monthStr/statCargoKind/tonQ/workTh，月度×货类）\\n\\n**同比/环比分析：**\\n- 年度同比 → getThroughputAnalysisYoyMomByYear（regionName/qty/statType/dateType，多港区×多统计类型）\\n- 月度同比 → getThroughputAnalysisYoyMomByMonth（regionName/qty/yoyQty/momQty，多港区）\\n- 集装箱同比 → getContainerAnalysisYoyMomByYear（regionName/qty/statType/dateType）\\n\\n**按港区/业务对比：**\\n- 各港区集装箱 → getContainerByBusinessType（regionName/totalTeu，按月）\\n- 各港区油化散杂 → getOilsChemBreakBulkByBusinessType（regionName/oilChemical/breakBulk）\\n- 各公司吞吐 → getPortCompanyThroughput（需 date + cmpName）\\n\\n**KPI快照（不可做趋势）：**\\n- 目标完成率 → getThroughputAndTargetThroughputTon（targetQty/finishQty，仅1行）\\n- TEU目标 → getThroughputAndTargetThroughputTeu（targetQty/finishQty，仅1行）\\n\\n### D2 市场商务分析策略\\n- 当月吞吐概览 → getCurBusinessDashboardThroughput（num/typeName 透视格式）\\n- 累计吞吐概览 → getSumBusinessDashboardThroughput（num/typeName 透视格式）\\n- 各港区累计 → getCumulativeRegionalThroughput（num/typeName/zoneName 透视格式）\\n- 各港区当月占比 → getMonthlyRegionalThroughputAreaBusinessDashboard（num/typeName/zoneName 透视格式）\\n- 月度趋势（按业务板块）→ getTrendChart（throughput/businessSegment/dateMonth，需传 businessSegment+startDate+endDate）\\n- 累计趋势（按业务板块）→ getCumulativeTrendChart（throughput/businessSegment/dateYear）\\n- 重点企业排名 → getKeyEnterprise（throughput/companyName/dateMonth，需传 businessSegment）\\n- 注意：D2 很多 API 返回 num/typeName 透视格式，需按 typeName 分组提取数值\\n\\n### 图表选择\\n- 吞吐量目标完成分析 → skill_chart_bar（目标 vs 实际）\\n- 月度趋势分析 → skill_chart_line（当年 vs 上年曲线）\\n- 港区/业务结构对比 → skill_chart_bar\\n- 完成进度归因 → skill_chart_waterfall\\n\"}','2026-04-21 16:42:56','2026-04-23 18:25:01');
/*!40000 ALTER TABLE `employees` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `report_artifacts`
--

DROP TABLE IF EXISTS `report_artifacts`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `report_artifacts` (
  `id` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `session_id` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `task_id` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `skill_id` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `format` varchar(16) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'html / docx / pptx / markdown',
  `title` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `file_path` varchar(512) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Path relative to REPORTS_DIR',
  `size_bytes` bigint DEFAULT NULL,
  `status` varchar(16) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'ready' COMMENT 'ready / failed',
  `meta` json DEFAULT NULL COMMENT 'slide_count / mode / chart_count etc.',
  `created_at` datetime NOT NULL DEFAULT (now()),
  PRIMARY KEY (`id`),
  KEY `idx_report_artifacts_session` (`session_id`,`created_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `report_artifacts`
