CREATE TABLE `sessions` (
  `session_id` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `user_id` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `employee_id` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `state_json` json DEFAULT NULL,
  `created_at` datetime DEFAULT (now()),
  `updated_at` datetime DEFAULT (now()),
  `title` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `pinned` smallint NOT NULL DEFAULT '0',
  `deleted_at` datetime DEFAULT NULL,
  PRIMARY KEY (`session_id`),
  KEY `ix_sessions_user_id` (`user_id`),
  KEY `ix_sessions_employee_id` (`employee_id`),
  KEY `idx_sessions_active` (`user_id`,`updated_at`),
  KEY `idx_sessions_user_updated` (`user_id`,`updated_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

