_volume\'} error_message=None elapsed_seconds=0.0773240420021466 attempt_count=1 error_category=None llm_tokens={}\", \"T015\": \"skill_id=\'skill_desc_analysis\' status=\'success\' output_type=\'json\' data={\'summary_stats\': {\'typeName_实物资产数\': {\'num\': {\'mean\': 59420102.77, \'median\': 16050.85, \'std\': 188379209.04, \'min\': 208.5, \'max\': 752724109.4, \'missing_rate\': 0.0}}, \'typeName_资产净值\': {\'num\': {\'mean\': 114234228.18, \'median\': 14726.2, \'std\': 267021914.38, \'min\': 1598.4, \'max\': 713017653.0, \'missing_rate\': 0.0}}, \'typeName_资产原值\': {\'num\': {\'mean\': 58804275.85, \'median\': 17061.1, \'std\': 171309130.13, \'min\': 1607.4, \'max\': 553932315.5, \'missing_rate\': 0.0}}, \'typeName_面积\': {\'num\': {\'mean\': 17924.66, \'median\': 14075.85, \'std\': 13424.26, \'min\': 736.2, \'max\': 41102.2, \'missing_rate\': 0.0}}}, \'growth_rates\': {}, \'narrative\': \'从资产净值规模看，港区间差异极为显著，头部港区占据绝对主导地位，资产净值最高的三个港区集中体现了资源集聚效应，反映出资产布局呈现明显集中化态势。整体实物资产数量、资产原值与净值均呈现高度右偏分布，均值远高于中位数，表明极少数大型港区对整体统计数据产生显著影响，多数港区资产规模相对较小。\\\\n\\\\n在资产结构方面，设备设施、房屋及土地海域三类资产的分布不均，其中设备设施类资产在净值和原值中占比较高，显示出资本密集型特征。尽管具体同比变动方向尚不明确，但结合资产规模离散程度高、标准差巨大等特点，可判断各类资产在区域间配置不均衡，核心港区持续集中承载高价值资产，整体布局趋向于中心化集聚而非均匀分散。\'} storage_ref=None metadata={\'rows_analyzed\': 56, \'columns_analyzed\': [\'num\'], \'group_by\': \'typeName\', \'narrative_domain\': \'generic\', \'narrative_error_category\': None, \'focus_points_count\': 4} error_message=None elapsed_seconds=22.2015555830003 attempt_count=1 error_category=None llm_tokens={\'prompt\': 475, \'completion\': 178}\", \"T016\": \"skill_id=\'skill_attribution\' status=\'partial\' output_type=\'json\' data={\'primary_drivers\': [], \'secondary_factors\': [], \'uncertainty_note\': \'LLM 输出无法解析为 JSON\', \'narrative\': \'{\\\\n  \\\"primary_drivers\\\": [\\\\n    {\\\\n      \\\"factor\\\": \\\"丹东港支付完成率异常偏高\\\",\\\\n      \\\"direction\\\": \\\"+\\\",\\\\n      \\\"estimated_impact\\\": \\\"约+35%\\\",\\\\n      \\\"evidence\\\": \\\"T007数据显示，丹东港计划支付金额为180,616.8万元，实际支付达80,453.4万元，支付完成率44.5%，远高于其投资完成率（0.5%），表明存在大量未匹配投资的支付行为，可能为预付款或数据错配，显著扭曲整体支付完成率。\\\"\\\\n    },\\\\n    {\\\\n      \\\"factor\\\": \\\"营口港投资与支付双低但支付完成率畸高\\\",\\\\n      \\\"direction\\\": \\\"+\\\",\\\\n      \\\"estimated_impact\\\": \\\"约+20%\\\",\\\\n      \\\"evidence\\\": \\\"营口港计划投资131,970.3万元，实际投资164,408.7万元（完成率124.6%），但计划支付仅6,393.6万元，实际支付39,567.2万元，支付完成率高达618.9%，表明支付口径与投资严重不匹配，推高整体支付完成率。\\\"\\\\n    }\\\\n  ],\\\\n  \\\"secondary_factors\\\": [\\\\n    {\\\\n      \\\"factor\\\": \\\"2025年计划支付骤降\\\",\\\\n      \\\"direction\\\": \\\"-\\\",\\\\n      \\\"estimated_impact\\\": \\\"约-15%\\\",\\\\n      \\\"evidence\\\": \\\"T006显示2025年计划支付金额为59,758.7万元，较2024年26,297.0万元虽有上升，但实际支付仅2,316.8万元，完成率3.9%，反映当年支付执行严重滞后，可能受审批或资金拨付延迟影响。\\\"\\\\n    },\\\\n    {\\\\n      \\\"factor\\\": \\\"未开工项目集中在部分港区\\\",\\\\n      \\\"direction\\\": \\\"-\\\",\\\\n      \\\"estimated_impact\\\": \\\"约-10%\\\",\\\\n      \\\"evidence\\\": \\\"T009显示各港区大量项目处于\\\\\'配置\\\\\'阶段（大连港195个、丹东港116个等），结合T010中\\\\\'captProjectQty\\\\\'为1但\\\\\'deliveryCaptProjectQty\\\\\'为0，表明项目整体开工率极低，形成交付瓶颈。\\\"\\\\n    }\\\\n  ],\\\\n  \\\"uncertainty_note\\\": \\\"数据存在显著口径不一致问题：T007中丹东港、营口港支付金额远超计划，与投资进度脱节，可能因支付定义包含非资本性支出或数据归集错误；T010数据几乎为空，无法有效反映项目交付进展；T008中projectQty与支付金额量级不匹配（如2026年840项目对应285亿元支付），疑似单位错误或聚合逻辑异常。整体归因受限于数据质量，部分结论基于异常值反向推断。\\\",\\\\n  \\\"narrative\\\": \\\"整体支付完成率（T007聚合）的异常上升主要由丹东港和营口港的支付数据畸高驱动。丹东港计划支付18.06亿元，实际支付8.05亿元，完成率44.5%，但其投资完成率仅0.5%（1,090.2万元/21.8亿元），表明支付行为未伴随实质性投资进展，可能为预付款或成本归集错误。营口港更出现支付完成率618.9%的极端值，反映支付与投资计划严重脱节。这两个港区的数据异常显著拉高了整体支付完成率，形成‘高完成’假象。\\\",\\\\n    \\\"项目执行层面存在明显瓶颈。T009显示所有港区均有大量项目停留在‘配置’阶段，结合T010中仅1个项目被标记但未交付，表明项目审批后未能有效转入实施。历史节奏对比（T006）显示2025年实际支付仅完成3.9%，远低于往年水平，反映资金拨付或审批流程存在延迟。数据质量问题严重制约分析可靠性，特别是支付与投资口径不一致、项目数量与金额不匹配等问题，可能导致归因偏差。\\\"\\\\n  },\\\\n  \\\"waterfall_data\\\": [\\\\n    {\\\\n      \\\"name\\\": \\\"基准值\\\",\\\\n      \\\"value\\\": 100\\\\n    },\\\\n    {\\\\n      \\\"name\\\": \\\"丹东港支付异常贡献\\\",\\\\n      \\\"value\\\": 35\\\\n    },\\\\n    {\\\\n      \\\"name\\\": \\\"营口港支付畸高贡献\\\",\\\\n      \\\"value\\\": 20\\\\n    },\\\\n    {\\\\n      \\\"name\\\": \\\"2025年支付执行滞后\\\",\\\\n      \\\"value\\\": 5\\\\n    },\\\\n    {\\\\n      \\\"name\\\": \\\"未开工项目占比高\\\",\\\\n      \\\"value\\\": -10\\\\n    },\\\\n    {\\\\n      \\\"name\\\": \\\"汇总\\\",\\\\n      \\\"value\\\": 150\\\\n    }\\\\n  ]\\\\n}\', \'waterfall_data\': []} storage_ref=None metadata={\'raw_response_length\': 1996, \'domain\': \'generic\'} error_message=None elapsed_seconds=46.94893291700282 attempt_count=1 error_category=\'PARSE_ERROR\' llm_tokens={\'prompt\': 1303, \'completion\': 1064}\", \"T017\": \"skill_id=\'skill_desc_analysis\' status=\'success\' output_type=\'json\' data={\'summary_stats\': {\'usageRate\': {\'mean\': 5.12, \'median\': 4.75, \'std\': 2.25, \'min\': 3.1, \'max\': 7.9, \'missing_rate\': 0.75}, \'serviceableRate\': {\'mean\': 0.98, \'median\': 0.98, \'std\': 0.02, \'min\': 0.96, \'max\': 1.0, \'missing_rate\': 0.75}, \'machineHourRate\': {\'mean\': 13.8, \'median\': 13.55, \'std\': 0.61, \'min\': 13.4, \'max\': 14.7, \'missing_rate\': 0.75}}, \'growth_rates\': {}, \'narrative\': \'设备使用率均值为5.12%，呈现一定波动性（标准差2.25%），最低值出现在3.1%，表明部分月份存在设备闲置或调度不足问题。相比之下，服务完好率整体维持在高位（均值98%，最小值96%），波动较小，说明设备维护水平稳定，未出现大规模突发故障。二者趋势未显著协同改善，提示使用率提升可能更多受作业需求驱动，而非设备可用性限制。\\\\n\\\\n机器台时效率均值达13.8箱/小时，波动较小，环比变化平稳，反映现场操作效率较为稳定。完好率低谷月份未对应明显的效率下滑，说明即便在设备轻微故障增多时段，生产组织仍保持韧性，未显著影响集装箱处理效率。总体来看，设备运营可靠性较高，核心瓶颈更可能来自调度或业务量波动，而非设备故障。\'} storage_ref=None metadata={\'rows_analyzed\': 16, \'columns_analyzed\': [\'usageRate\', \'serviceableRate\', \'machineHourRate\'], \'group_by\': None, \'narrative_domain\': \'generic\', \'narrative_error_category\': None, \'focus_points_count\': 4} error_message=None elapsed_seconds=12.621268791001057 attempt_count=1 error_category=None llm_tokens={\'prompt\': 305, \'completion\': 188}\", \"T018\": \"skill_id=\'skill_chart_bar\' status=\'success\' output_type=\'chart\' data={\'title\': {\'text\': \'资产统计\', \'left\': \'