'color\': \'#1E3A5F\'}}, \'tooltip\': {\'trigger\': \'axis\'}, \'legend\': {\'data\': [\'战略吞吐量\', \'战略客户累计吞吐量\', \'累计收入(万元)\', \'贡献率(%)\'], \'bottom\': 0}, \'xAxis\': {\'type\': \'category\', \'data\': [\'2026-01\', \'2026-02\', \'2026-03\', \'2026-04\', \'2026-05\', \'2026-06\']}, \'yAxis\': {\'type\': \'value\', \'name\': \'\'}, \'series\': [{\'name\': \'战略吞吐量\', \'type\': \'line\', \'data\': [1725.5, 1485.9, 2147.7, 2242.6, 2250.3, 2229.4], \'smooth\': True, \'lineStyle\': {\'color\': \'#1E3A5F\'}, \'itemStyle\': {\'color\': \'#1E3A5F\'}}, {\'name\': \'战略客户累计吞吐量\', \'type\': \'line\', \'data\': [1725.5, 3211.4, 5359.1, 7601.6, 9851.9, 12081.4], \'smooth\': True, \'lineStyle\': {\'color\': \'#F0A500\'}, \'itemStyle\': {\'color\': \'#F0A500\'}}, {\'name\': \'累计收入(万元)\', \'type\': \'line\', \'data\': [2077.0, 3960.4, 6928.6, 9686.1, 12521.2, 15661.0], \'smooth\': True, \'lineStyle\': {\'color\': \'#E85454\'}, \'itemStyle\': {\'color\': \'#E85454\'}}, {\'name\': \'贡献率(%)\', \'type\': \'line\', \'data\': [67.7, 64.55, 63.4, 64.05, 62.5, 61.0], \'smooth\': True, \'lineStyle\': {\'color\': \'#4CAF50\'}, \'itemStyle\': {\'color\': \'#4CAF50\'}}], \'color\': [\'#1E3A5F\', \'#F0A500\', \'#E85454\', \'#4CAF50\']} storage_ref=None metadata={\'chart_type\': \'line\', \'chart_subtype\': \'single_y\', \'series_count\': 4, \'rows\': 6} error_message=None elapsed_seconds=6.009874667000986 attempt_count=1 error_category=None llm_tokens={}\", \"T018\": \"skill_id=\'skill_summary_gen\' status=\'success\' output_type=\'text\' data=\'当前客户总量9454户，策略客户仅33户，占比不足0.35%，渗透率极低。出港量占比超95%，业务高度依赖单向物流，回程资源利用不足风险突出。三大货类（有色金属、机械、农副）占整体货量近七成，客户集中于能源、汽车、基建领域，头部效应显著，但抗风险能力偏弱。集装箱业务占比从48.5%降至38%，增长放缓拖累整体增速。\\\\n\\\\n**最大风险**：业务结构单一，客户与货类集中度高，叠加回程空载压力，资产周转效率承压。\\\\n\\\\n**建议**：1）聚焦能源、汽车等核心客户，深化增值服务，提升粘性；2）推动返程货源整合，探索散杂货与油化品等高潜力品类拓展，优化网络协同。\' storage_ref=None metadata={\'source_count\': 3, \'upstream_dropped_failed\': 0, \'summary_style\': \'executive\', \'domain\': \'generic\'} error_message=None elapsed_seconds=7.642573458000697 attempt_count=1 error_category=None llm_tokens={\'prompt\': 902, \'completion\': 188}\", \"T020\": \"skill_id=\'skill_report_html\' status=\'success\' output_type=\'file\' data=\'<!DOCTYPE html>\\\\n<html lang=\\\"zh-CN\\\">\\\\n<head>\\\\n<meta charset=\\\"utf-8\\\">\\\\n<meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\">\\\\n<title>2026年4月市场客户与战略客户洞察报告</title>\\\\n<script src=\\\"https://cdn.jsdelivr.net/npm/echarts@5/dist/echarts.min.js\\\"></script>\\\\n<style>\\\\nbody { font-family: \\\\\'Microsoft YaHei\\\\\', sans-serif; max-width: 1000px; margin: 0 auto; padding: 20px; color: #333333; }\\\\nh1 { color: #1E3A5F; text-align: center; border-bottom: 3px solid #F0A500; padding-bottom: 10px; }\\\\nh2 { color: #1E3A5F; margin-top: 30px; }\\\\nh3 { color: #2D5F8A; }\\\\n.meta { text-align: center; color: #666; margin-bottom: 30px; }\\\\n.section { margin-bottom: 40px; }\\\\n.chart-container { width: 100%; height: 400px; margin: 20px 0; }\\\\n.narrative { line-height: 1.8; text-indent: 2em; }\\\\n.summary { background: #1E3A5F; color: white; padding: 20px; border-radius: 8px; margin-top: 40px; }\\\\n.summary h2 { color: #F0A500; }\\\\ntable.stats { width: 100%; border-collapse: collapse; margin: 16px 0; }\\\\ntable.stats th { background: #1E3A5F; color: white; padding: 8px 12px; text-align: left; font-size: 13px; }\\\\ntable.stats td { padding: 8px 12px; border-bottom: 1px solid #e0e0e0; font-size: 13px; font-family: \\\\\'Calibri\\\\\', monospace; }\\\\ntable.stats tr:nth-child(even) { background: #F5F7FA; }\\\\n.kpi-row { display: flex; gap: 16px; margin: 16px 0; flex-wrap: wrap; }\\\\n.kpi-card { flex: 1; min-width: 180px; background: #F5F7FA; border-radius: 8px; padding: 16px; text-align: center; border-left: 4px solid #F0A500; }\\\\n.kpi-card .label { font-size: 12px; color: #546E7A; margin-bottom: 4px; }\\\\n.kpi-card .value { font-size: 28px; font-weight: bold; font-family: \\\\\'Calibri\\\\\', monospace; }\\\\n.kpi-card .value.positive { color: #2E7D32; }\\\\n.kpi-card .value.negative { color: #C62828; }\\\\n.kpi-card .sub { font-size: 11px; color: #546E7A; }\\\\n</style>\\\\n</head>\\\\n<body>\\\\n<h1>2026年4月市场客户与战略客户洞察报告</h1>\\\\n<div class=\\\"meta\\\">市场商务与战略客户洞察专家 | 2026-04-20</div>\\\\n<div class=\\\"section\\\"><h2>一、经营摘要</h2>\\\\n<div class=\\\"narrative\\\">当前客户总量达9454户，其中策略客户仅33户，占比不足0.35%，表明策略客户渗透率极低，客户结构仍以普通自然人和机关团体为主。出港量（6298.0）占总业务量（6632.0）的95%以上，显示业务高度依赖出港环节，整体运营集中于单向物流场景，可能存在回程资源利用率不足的风险，建议探索返程货源整合或优化调度机制以提升资产周转效率。\\\\n\\\\n从行业货类结构看，有色金属（196.0）、机械设备（185.0）和农副产品（125.0）为三大主力品类，合计占整体货量的近七成。相比之下，木材（7.0）和日用百货（18.0）等品类规模极小，呈现明显断层。货类集中度较高反映出业务聚焦于大宗工业品运输，但同时也暴露了抗风险能力较弱的问题——若主要行业需求波动，整体业绩将受到显著冲击，建议在巩固现有优势品类的同时，适度拓展关联性强、运输特性相近的新品类以增强业务韧性。</div>\\\\n<h3>统计数据概览</h3><table class=\\\"stats\\\"><tr><th>指标</th><th>均值</th><th>中位数</th><th>标准差</th><th>最小值</th><th>最大值</th></tr><tr><td><b>indstryFieldName_其他/qty</b></td><td>57.00</td><td>-</td><td>-</td><td>57.00</td><td>57.00</td></tr><tr><td><b>indstryFieldName_农副产品/qty</b></td><td>125.00</td><td>-</td><td>-</td><td>125.00</td><td>125.00</td></tr><tr><td><b>indstryFieldName_化肥/qty</b></td><td>121.00</td><td>-</td><td>-</td><td>121.00</td><td>121.00</td></tr><tr><td><b>indstryFieldName_建材/qty</b></td><td>82.00</td><td>-</td><td>-</td><td>82.00</td><td>82.00</td></tr><tr><td><b>indstryFieldName_日用百货/qty</b></td><td>18.00</td><td>-</td><td>-</td><td>18.00</td><td>18.00</td></tr><tr><td><b>indstryFieldName_有色金属/qty</b></td><td>196.00</td><td>-</td><td>-</td><td>196.00</td><td>196.00</td></tr><tr><td><b>indstryFieldName_木材/qty</b></td><td>7.00</td><td>-</td><td>-</td><td>7.00</td><td>7.00</td></tr><tr><td><b>indstryFieldName_机械设备/qty</b></td><td>185.00</td><td>-</td><td>-</td><td>185.00</td><td>185.00</td></tr><tr><td><b>indstryFieldName_水泥/qty</b></td><td>162.00</td><td>-</td><td>-</td><td>162.00</td><td>162.00</td></tr><tr><td><b>indstryFieldName_汽车/qty</b></td><td>151.00</td><td>-</td><td>-</td><td>151.00</td><td>151.00</td></tr><tr><td><b>indstryFieldName_煤炭/qty</b></td><td>5.00</td><td>-</td><td>-</td><td>5.00</td><td>5.00</td></tr><tr><td><b>indstryFieldName_石油化工/qty</b></td><td>48.00</td><td>-</td><td>-</td><td>48.00</td><td>48.00</td></tr><tr><td><b>indstryFieldName_矿石/qty</b></td><td>182.00</td><td>-</td><td>-</td><td>182.00</td><td>182.00</td></tr><tr><td><b>indstryFieldName_粮食/qty</b></td><td>120.00</td><td>-</td><td>-</td><td>120.00</td><td>120.00</td></tr><tr><td><b>indstryFieldName_纸浆/qty</b></td><td>60.00</td><td>-</td><td>-</td><td>60.00</td><td>60.00</td></tr><tr><td><b>indstryFieldName_钢材/qty</b></td><td>151.00</td><td>-</td><td>-</td><td>151.00</td><td>151.00</td></tr><tr><td><b>indstryFieldName_集装箱/qty</b></td><td>117.00</td><td>-</td><td>-</td><td>117.00</td><td>117.00</td></tr></table>\\\\n</div>\\\\n<div class=\\\"section\\\"><h2>二、客户结构分析</h2>\\\\n<div class=\\\"narrative\\\">从客户维度看，头部客户集中度较为显著，中国华电集团、一汽集团等企业贡献了较高的数值规模，其最新值分别达到196.2和194.7，位居前两位。上汽通用五菱紧随其后，数值为176.2，显示出能源、汽车制造类客户在当前业务结构中占据主导地位。相比之下，日本海洋网联船务的数值仅为22.7，明显低于头部客户，反映出客户间业务体量存在明显分层。\\\\n\\\\n在业务类型分布上，散杂货与集装箱构成主要类别，但不同客户在这两类之间的布局差异显著。例如中远海运集团和马士基航运作为典型航运企业，其业务集中在集装箱领域，而中国交建、中国能建等工程类企业则更多关联散杂货运输。这种结构性差异表明，客户行业属性与业务品类高度相关，建议后续资源投放可结合行业特征进行差异化配置。\\\\n\\\\n整体来看，各客户数据无时间序列波动，所有观测值均为单一时间点记录，因此当前呈现的是静态规模对比而非动态趋势。在此前提下，关键信号集中于结构分布而非变化节奏，其中能源、基建与汽车制造三大行业头部客户构成了当前业务的核心支柱，合计贡献了超过半数的重点客户份额，是后续客户运营和增值服务落地的重点锚点。</div>\\\\n<h3>统计数据概览</h3><table class=\\\"stats\\\"><tr><th>指标</th><th>均值</th><th>中位数</th><th>标准差</th><th>最小值</th><th>最大值</th></tr><tr><td><b>clientName_ONE(日本海洋网联船务)/num</b></td><td>22.70</td><td>-</td><td>-</td><td>22.70</td><td>22.70</td></tr><tr><td><b>clientName_一汽集团/num</b></td><td>194.70</td><td>-</td><td>-</td><td>194.70</td><td>194.70</td></tr><tr><td><b>clientName_上汽通用五菱/num</b></td><td>176.20</td><td>-</td><td>-</td><td>176.20</td><td>176.20</td></tr><tr><td><b>clientName_东北特殊钢集团股份有限公司/num</b></td><td>104.60</td><td>-</td><td>-</td><td>104.60</td><td>104.60</td></tr><tr><td><b>clientName_中国交通建设集