\'completion\': 178}\", \"T016\": \"skill_id=\'skill_attribution\' status=\'success\' output_type=\'json\' data={\'primary_drivers\': [{\'factor\': \'realFinishPayAmt\', \'direction\': \'-\', \'estimated_impact\': \'约-77%\', \'evidence\': \'T006中realFinishPayAmt从均值62849.13下降至最新值21913.1，降幅显著；T008中realFinishPayAmt最新值为2158250.0，但仅2行数据且年份为2025-2026，可能反映项目周期性支付低谷。T010显示realFinishPayAmt为0，表明部分项目无实际支付发生。\'}, {\'factor\': \'planPayAmt\', \'direction\': \'-\', \'estimated_impact\': \'约-45%\', \'evidence\': \'T007中planPayAmt最新值为112876.8，低于均值103854.42，虽略高于均值但结合T010中planPayAmt为0，表明部分区域或项目取消或推迟支付计划，形成结构性下降。\'}], \'secondary_factors\': [{\'factor\': \'projectQty\', \'direction\': \'-\', \'estimated_impact\': \'约-10%\', \'evidence\': \'T009中projectQty最新值为38.0，远低于均值99.6，显示在建或活跃项目数量减少；T008中projectQty最新值为880.0，处于高位，但与T009不一致，可能反映不同统计口径（总体vs阶段项目），存在结构差异。\'}, {\'factor\': \'finishInvestAmt\', \'direction\': \'-\', \'estimated_impact\': \'约-25%\', \'evidence\': \'T006中finishInvestAmt最新值80666.0低于均值108570.57；T007中最新值84045.1亦低于均值83133.88，虽接近但结合多表趋势，投资完成额呈放缓迹象。\'}], \'uncertainty_note\': \'数据表间时间跨度不一致（如T008为2025-2026，T006最新为2026），且部分表行数极少（如T010仅1行），导致趋势判断存在时序错位风险；不同表中realFinishPayAmt量级差异巨大（T006为万级，T008为百万级），可能属于不同项目群，归因需谨慎。置信度中等。\', \'narrative\': \'从数据可观察到，实际支付金额（realFinishPayAmt）在多个表中呈现显著下降趋势，是导致当前指标下滑的最直接驱动因素。T006中该值从历史均值6.28万降至2.19万，降幅超65%；T010中甚至为0，表明部分项目无实际支付活动。结合T007中计划支付金额（planPayAmt）在部分区域也出现回落，说明支付意愿或执行能力减弱，可能反映项目进入尾声或资金拨付延迟。\\\\n\\\\n项目数量（projectQty）在T009中从均值99.6降至38.0，显示活跃项目规模收缩，进一步抑制支付与投资活动。尽管T008中项目总数较高，但其统计范围可能包含远期规划项目，与T009中按阶段统计的‘当前活跃’项目不一致，形成结构性差异。整体来看，支付执行与计划双降，叠加项目活跃度降低，共同构成指标下滑的主要归因路径。\', \'waterfall_data\': [{\'name\': \'基准值\', \'value\': 100}, {\'name\': \'realFinishPayAmt下降\', \'value\': -77}, {\'name\': \'planPayAmt减少\', \'value\': -45}, {\'name\': \'projectQty减少\', \'value\': -10}, {\'name\': \'finishInvestAmt放缓\', \'value\': -25}, {\'name\': \'汇总\', \'value\': -57}]} storage_ref=None metadata={\'refs_used\': [\'T006\', \'T007\', \'T008\', \'T009\', \'T010\'], \'sou